# Script: menu_servicio.ps1
# Uso: .\menu_servicio.ps1 -Servicio "wuauserv"

param(
    [Parameter(Mandatory=$true)]
    [string]$Servicio
)

# --- Validación ---
if (-not (Get-Service -Name $Servicio -ErrorAction SilentlyContinue)) {
    Write-Error "El servicio '$Servicio' no existe"
    exit 1
}

# --- Menú principal ---
do {
    Write-Host "`n=== MENÚ: $Servicio ==="
    Write-Host "1) Ver estado"
    Write-Host "2) Reiniciar servicio"
    Write-Host "3) Salir"
    $opcion = Read-Host "Opción"

    switch ($opcion) {
        "1" {
            $svc = Get-Service -Name $Servicio
            Write-Host "Estado: $($svc.Status)"
        }
        "2" {
            Restart-Service -Name $Servicio
            Write-Host "Servicio reiniciado correctamente"
        }
        "3" {
            Write-Host "Saliendo..."
        }
        default {
            Write-Host "Opción inválida"
        }
    }
} while ($opcion -ne "3")

# Script: backup_archivos.ps1
# Uso: .\backup_archivos.ps1 -Origen C:\datos -Destino C:\backup -Extension log

param(
    [Parameter(Mandatory=$true)]
    [string]$Origen,

    [Parameter(Mandatory=$true)]
    [string]$Destino,

    [string]$Extension = "log"
)

# --- Validación ---
if (-not (Test-Path $Origen)) {
    Write-Error "Directorio origen no existe: $Origen"
    exit 1
}

# --- Crear destino si no existe ---
if (-not (Test-Path $Destino)) {
    New-Item -ItemType Directory -Path $Destino | Out-Null
    Write-Host "Directorio creado: $Destino"
}

$LogFile = "C:\temp\backup.log"
New-Item -ItemType Directory -Path "C:\temp" -Force | Out-Null

# --- Copiar archivos ---
$archivos = Get-ChildItem -Path $Origen -Filter "*.$Extension"

foreach ($archivo in $archivos) {
    try {
        Copy-Item -Path $archivo.FullName -Destination $Destino -ErrorAction Stop
        $linea = "$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss') | OK    | $($archivo.Name)"
    } catch {
        $linea = "$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss') | ERROR | $($archivo.Name) - $($_.Exception.Message)"
    }
    Add-Content -Path $LogFile -Value $linea
    Write-Host $linea
}

Write-Host "`nProceso completado. Log en: $LogFile"

# Script: crear_usuarios.ps1
# Uso: .\crear_usuarios.ps1 -Fichero usuarios.csv
# CSV: Nombre,Grupo

param(
    [Parameter(Mandatory=$true)]
    [string]$Fichero
)

if (-not (Test-Path $Fichero)) {
    Write-Error "Fichero no encontrado: $Fichero"
    exit 1
}

$creados = 0
$existentes = 0

# --- Contraseña por defecto segura ---
$passwordSegura = ConvertTo-SecureString "Temporal@2024" -AsPlainText -Force

$usuarios = Import-Csv -Path $Fichero

foreach ($fila in $usuarios) {
    $nombre = $fila.Nombre
    $grupo  = $fila.Grupo

    if (Get-LocalUser -Name $nombre -ErrorAction SilentlyContinue) {
        Write-Host "Aviso: '$nombre' ya existe"
        $existentes++
    } else {
        New-LocalUser -Name $nombre -Password $passwordSegura -FullName $nombre
        Add-LocalGroupMember -Group $grupo -Member $nombre
        Write-Host "Creado: $nombre (grupo: $grupo)"
        $creados++
    }
}

Write-Host "`nResumen: $creados creados, $existentes ya existían"
